arguments.command:
cd /tmp && mkdir -p stackalloc-test && cd stackalloc-test && dotnet new console --force -q && cat > Program.cs << 'EOF'
using System;

// Test stackalloc Span<nint> and Span<nuint>
Span<nint> signedSpan = stackalloc nint[4];
for (int i = 0; i < signedSpan.Length; i++)
    signedSpan[i] = (nint)(i * 10);

Console.WriteLine($"Span<nint> length: {signedSpan.Length}");
for (int i = 0; i < signedSpan.Length; i++)
    Console.WriteLine($"  signedSpan[{i}] = {signedSpan[i]}");

Span<nuint> unsignedSpan = stackalloc nuint[3];
for (int i = 0; i < unsignedSpan.Length; i++)
    unsignedSpan[i] = (nuint)(i * 100);

Console.WriteLine($"Span<nuint> length: {unsignedSpan.Length}");
for (int i = 0; i < unsignedSpan.Length; i++)
    Console.WriteLine($"  unsignedSpan[{i}] = {unsignedSpan[i]}");

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
EOF
dotnet run 2>&1

